// pages/Home.jsx — Landing page with hero + topic list
import React, { useState } from "react";
import Hero from "../components/Hero";
import TopicList from "../components/TopicList";
import { TOPICS } from "../data/topicsData";

export default function Home() {
  const [searchQuery, setSearchQuery] = useState("");

  // Filter topics by search query (name or category)
  const filteredTopics = TOPICS.filter((topic) => {
    const q = searchQuery.toLowerCase();
    return (
      topic.name.toLowerCase().includes(q) ||
      topic.category.toLowerCase().includes(q)
    );
  });

  return (
    <main className="max-w-5xl mx-auto px-5">
      <Hero searchQuery={searchQuery} onSearchChange={setSearchQuery} />

      {/* Divider */}
      <div className="border-t border-border mb-8" />

      {/* Section heading */}
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-sm font-mono text-muted uppercase tracking-widest">
          All Topics
        </h2>
        <span className="text-xs text-muted">{filteredTopics.length} topics</span>
      </div>

      {/* Topic list */}
      <TopicList topics={filteredTopics} />

      {/* Footer spacer */}
      <div className="h-20" />
    </main>
  );
}
